#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char s[100005]; scanf("%s", s);
        int cntR=0,cntG=0,cntB=0;
        for(int i=0;i<N;i++){
            if(s[i]=='R') cntR++;
            else if(s[i]=='G') cntG++;
            else if(s[i]=='B') cntB++;
        }
        int mx = cntR; if(cntG>mx) mx=cntG; if(cntB>mx) mx=cntB;
        printf("%d\n", N-mx);
    }
    return 0;
}

